CREATE TABLE community_wallets ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, wallet_address TEXT UNIQUE NOT NULL, omega_balance NUMERIC DEFAULT 0, role TEXT DEFAULT 'member', joined_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc', now()) ); CREATE TABLE agent_logs ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, agent_id TEXT NOT NULL, action TEXT NOT NULL, memory_payload JSONB, status TEXT DEFAULT 'success', executed_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc', now()) );
